"use client";
import { supabase } from "./lib/supabase";
import { useMemo, useState } from "react";

type Screen = "login" | "dashboard" | "clientes" | "prestamos" | "pagos";

type Cliente = {
  id: number;
  nombre: string;
  telefono: string;
  score: number;
  nivel: "VIP" | "BUENO" | "REGULAR" | "MOROSO";
};

type Prestamo = {
  id: number;
  clienteId: number;
  monto: number;
  interes: number;
  frecuencia: "DIARIO" | "SEMANAL" | "MENSUAL";
  cuotas: number;
  total: number;
  cuota: number;
  saldo: number;
  estado: "AL DÍA" | "COBRAR HOY" | "VENCIDO" | "PAGADO";
};

const clientesIniciales: Cliente[] = [
  { id: 1, nombre: "Juan Pérez", telefono: "611111111", score: 22, nivel: "VIP" },
  { id: 2, nombre: "María López", telefono: "622222222", score: 12, nivel: "BUENO" },
  { id: 3, nombre: "Pedro Ruiz", telefono: "633333333", score: 3, nivel: "REGULAR" },
  { id: 4, nombre: "Lucía Gómez", telefono: "644444444", score: -4, nivel: "MOROSO" },
];

const prestamosIniciales: Prestamo[] = [
  {
    id: 1,
    clienteId: 1,
    monto: 200,
    interes: 0.15,
    frecuencia: "DIARIO",
    cuotas: 20,
    total: 230,
    cuota: 11.5,
    saldo: 115,
    estado: "COBRAR HOY",
  },
  {
    id: 2,
    clienteId: 2,
    monto: 300,
    interes: 0.15,
    frecuencia: "SEMANAL",
    cuotas: 4,
    total: 345,
    cuota: 86.5,
    saldo: 172.5,
    estado: "AL DÍA",
  },
  {
    id: 3,
    clienteId: 4,
    monto: 150,
    interes: 0.1,
    frecuencia: "MENSUAL",
    cuotas: 2,
    total: 180,
    cuota: 90,
    saldo: 90,
    estado: "VENCIDO",
  },
];

function formatEUR(n: number) {
  return new Intl.NumberFormat("es-ES", {
    style: "currency",
    currency: "EUR",
  }).format(n);
}

function colorNivel(nivel: Cliente["nivel"]) {
  switch (nivel) {
    case "VIP":
      return "#15803d";
    case "BUENO":
      return "#16a34a";
    case "REGULAR":
      return "#d97706";
    case "MOROSO":
      return "#dc2626";
  }
}

function colorEstado(estado: Prestamo["estado"]) {
  switch (estado) {
    case "AL DÍA":
      return "#16a34a";
    case "COBRAR HOY":
      return "#d97706";
    case "VENCIDO":
      return "#dc2626";
    case "PAGADO":
      return "#2563eb";
  }
}

function cardStyle(): React.CSSProperties {
  return {
    background: "white",
    borderRadius: 18,
    padding: 16,
    boxShadow: "0 4px 14px rgba(0,0,0,0.06)",
    border: "1px solid #e5e7eb",
  };
}

function buttonStyle(primary = false): React.CSSProperties {
  return {
    padding: "12px 16px",
    borderRadius: 14,
    border: primary ? "none" : "1px solid #d1d5db",
    background: primary ? "#111827" : "white",
    color: primary ? "white" : "#111827",
    cursor: "pointer",
    fontWeight: 600,
  };
}

export default function App() {
  const [screen, setScreen] = useState<Screen>("login");
  const [clientes] = useState<Cliente[]>(clientesIniciales);
  const [prestamos] = useState<Prestamo[]>(prestamosIniciales);

  const totalPrestado = useMemo(
    () => prestamos.reduce((acc, p) => acc + p.monto, 0),
    [prestamos]
  );

  const totalPendiente = useMemo(
    () => prestamos.reduce((acc, p) => acc + p.saldo, 0),
    [prestamos]
  );

  const cobrosHoy = useMemo(
    () => prestamos.filter((p) => p.estado === "COBRAR HOY").length,
    [prestamos]
  );

  if (screen === "login") {
    return (
      <div
        style={{
          minHeight: "100vh",
          background: "#f3f4f6",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: 20,
        }}
      >
        <div style={{ ...cardStyle(), width: "100%", maxWidth: 380 }}>
          <h1 style={{ fontSize: 32, marginBottom: 8 }}>CREDI YA</h1>
          <p style={{ color: "#6b7280", marginBottom: 20 }}>
            Control de préstamos y cobros
          </p>

          <div style={{ display: "grid", gap: 12 }}>
            <input
              placeholder="Usuario"
              style={{
                padding: 12,
                borderRadius: 12,
                border: "1px solid #d1d5db",
              }}
            />
            <input
              placeholder="Contraseña"
              type="password"
              style={{
                padding: 12,
                borderRadius: 12,
                border: "1px solid #d1d5db",
              }}
            />
            <button style={buttonStyle(true)} onClick={() => setScreen("dashboard")}>
              Entrar
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: "#f9fafb", padding: 20 }}>
      <div style={{ maxWidth: 900, margin: "0 auto", display: "grid", gap: 20 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
          <div>
            <h1 style={{ margin: 0 }}>CREDI YA</h1>
            <p style={{ color: "#6b7280", marginTop: 6 }}>
              Gestión privada de clientes y préstamos
            </p>
          </div>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
            <button style={buttonStyle(screen === "dashboard")} onClick={() => setScreen("dashboard")}>
              Dashboard
            </button>
            <button style={buttonStyle(screen === "clientes")} onClick={() => setScreen("clientes")}>
              Clientes
            </button>
            <button style={buttonStyle(screen === "prestamos")} onClick={() => setScreen("prestamos")}>
              Préstamos
            </button>
            <button style={buttonStyle(screen === "pagos")} onClick={() => setScreen("pagos")}>
              Pagos
            </button>
          </div>
        </div>

        {screen === "dashboard" && (
          <>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
                gap: 16,
              }}
            >
              <div style={cardStyle()}>
                <p style={{ color: "#6b7280", margin: 0 }}>Total prestado</p>
                <h2>{formatEUR(totalPrestado)}</h2>
              </div>
              <div style={cardStyle()}>
                <p style={{ color: "#6b7280", margin: 0 }}>Saldo pendiente</p>
                <h2>{formatEUR(totalPendiente)}</h2>
              </div>
              <div style={cardStyle()}>
                <p style={{ color: "#6b7280", margin: 0 }}>Cobros hoy</p>
                <h2>{cobrosHoy}</h2>
              </div>
              <div style={cardStyle()}>
                <p style={{ color: "#6b7280", margin: 0 }}>Clientes</p>
                <h2>{clientes.length}</h2>
              </div>
            </div>

            <div style={cardStyle()}>
              <h3>Próximos cobros</h3>
              <div style={{ display: "grid", gap: 12 }}>
                {prestamos.map((p) => {
                  const cliente = clientes.find((c) => c.id === p.clienteId);
                  return (
                    <div
                      key={p.id}
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        gap: 12,
                        padding: 12,
                        border: "1px solid #e5e7eb",
                        borderRadius: 14,
                      }}
                    >
                      <div>
                        <strong>{cliente?.nombre}</strong>
                        <p style={{ margin: 0, color: "#6b7280" }}>
                          {p.frecuencia} · cuota {formatEUR(p.cuota)}
                        </p>
                      </div>
                      <span
                        style={{
                          background: "#f3f4f6",
                          color: colorEstado(p.estado),
                          padding: "6px 10px",
                          borderRadius: 999,
                          fontWeight: 700,
                          fontSize: 12,
                        }}
                      >
                        {p.estado}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          </>
        )}

        {screen === "clientes" && (
          <div style={{ ...cardStyle(), display: "grid", gap: 12 }}>
            <h3>Clientes</h3>
            {clientes.map((c) => (
              <div
                key={c.id}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                  padding: 12,
                  border: "1px solid #e5e7eb",
                  borderRadius: 14,
                }}
              >
                <div>
                  <strong>{c.nombre}</strong>
                  <p style={{ margin: 0, color: "#6b7280" }}>{c.telefono}</p>
                  <p style={{ margin: 0, color: "#6b7280" }}>Score: {c.score}</p>
                </div>
                <span
                  style={{
                    background: "#f3f4f6",
                    color: colorNivel(c.nivel),
                    padding: "6px 10px",
                    borderRadius: 999,
                    fontWeight: 700,
                    fontSize: 12,
                  }}
                >
                  {c.nivel}
                </span>
              </div>
            ))}
          </div>
        )}

        {screen === "prestamos" && (
          <div style={{ ...cardStyle(), display: "grid", gap: 12 }}>
            <h3>Préstamos</h3>
            {prestamos.map((p) => {
              const cliente = clientes.find((c) => c.id === p.clienteId);
              return (
                <div
                  key={p.id}
                  style={{
                    padding: 14,
                    border: "1px solid #e5e7eb",
                    borderRadius: 14,
                    display: "grid",
                    gap: 8,
                  }}
                >
                  <strong>{cliente?.nombre}</strong>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                    <span>Monto: {formatEUR(p.monto)}</span>
                    <span>Total: {formatEUR(p.total)}</span>
                    <span>Cuota: {formatEUR(p.cuota)}</span>
                    <span>Saldo: {formatEUR(p.saldo)}</span>
                  </div>
                  <span
                    style={{
                      width: "fit-content",
                      background: "#f3f4f6",
                      color: colorEstado(p.estado),
                      padding: "6px 10px",
                      borderRadius: 999,
                      fontWeight: 700,
                      fontSize: 12,
                    }}
                  >
                    {p.estado}
                  </span>
                </div>
              );
            })}
          </div>
        )}

        {screen === "pagos" && (
          <div style={{ ...cardStyle(), display: "grid", gap: 12 }}>
            <h3>Pagos</h3>
            <p style={{ color: "#6b7280" }}>
              Aquí irá el registro de pagos y los recibos.
            </p>
            <button
  style={buttonStyle(true)}
  onClick={async () => {
    const { error } = await supabase.from("clientes").insert([
      {
        nombre: "Cliente prueba",
        telefono: "600000000",
        direccion: "Calle prueba 1",
        trabajo: "Prueba",
        referencia: "Nadie",
        notas: "Insertado desde la app",
        score: 0,
      },
    ]);

    if (error) {
      console.log(error);
      alert("Error al guardar");
    } else {
      alert("Cliente guardado correctamente");
    }
  }}
>
  Probar guardado
</button>
          </div>
        )}
      </div>
    </div>
  );
}